import express from "express";
import http from "http";
import cors from "cors";
import path from "path";
import fs from "fs";
import { Server } from "colyseus";
import { WebSocketTransport } from "@colyseus/ws-transport";

// Импорты модулей
import { routerAuth } from "./routers/auth_routes.ts";
import { UniverseRoom } from "./wsRoom/UniverseRoom.ts";
import { corsOptions } from "./config/cors.ts";
import { connectDB } from "./config/connectDB.ts";

const __dirname = import.meta.dirname;
const port = Number(process.env.PORT || 8080);

const app = express();
const server = http.createServer(app);

// --- Кешируем index.html при запуске ---
const indexPath = path.join(__dirname, "public", "index.html");
const frontendUrl =
  process.env.FRONTEND_URL || "https://lost-space.vercel.app/";
let cachedHtml = "";
if (fs.existsSync(indexPath)) {
  cachedHtml = fs
    .readFileSync(indexPath, "utf8")
    .replace("window.FRONTEND_URL", `"${frontendUrl}"`);
}

// --- Middleware ---
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(cors(corsOptions));

// Debug логгер
app.use((req, res, next) => {
  console.log(`[DEBUG] ${req.method} ${req.path}`);
  if (req.method === "OPTIONS") return res.sendStatus(200);
  next();
});

// --- Настройка Colyseus ---
const gameServer = new Server({
  transport: new WebSocketTransport({ server }),
});
gameServer.define("GameRoom", UniverseRoom);

// --- Маршрутизация ---
app.use("/auth", routerAuth);
app.use("/matchmake", (req, res, next) =>
  (gameServer.transport as any).app(req, res, next),
);
app.use(express.static(path.join(__dirname, "public")));

app.get("/", (req, res) => res.send(cachedHtml));

// Ловушка для SPA (переписана проще через wildcard)
app.get(/^(?!\/auth|\/matchmake).*$/, (req, res, next) => {
  if (req.path.startsWith("/auth") || req.path.startsWith("/matchmake"))
    return next();
  res.redirect("/");
});

// --- Запуск ---
async function start() {
  await connectDB();
  server.listen(port, () => {
    console.log(`🎮 Игровой сервер Colyseus запущен на порту ${port}`);
  });
}

start();

