import { Request, Response, NextFunction } from "express";
import MailModel from "../models/chat.ts";

class MailController {
  // Получение входящих писем для конкретного игрока
  async getInbox(req: Request, res: Response, next: NextFunction) {
    try {
      const playerIdQuery = req.query.playerId;
      const playerId = Array.isArray(playerIdQuery)
        ? playerIdQuery[0]
        : playerIdQuery;

      if (!playerId || typeof playerId !== "string") {
        return res.status(400).json({ error: "Player ID is required" });
      }

      const letters = await MailModel.find({ receiverId: playerId })
        .sort({ timestamp: -1 }) // Сначала новые
        .lean();

      res.status(200).json(letters);
    } catch (error) {
      next(new Error("Failed to fetch inbox mail"));
    }
  }

  // Отправка официального письма на почту (сохраняется в БД)
  async createMail(req: Request, res: Response, next: NextFunction) {
    try {
      const { senderId, senderName, receiverId, subject, body } = req.body;

      const letter = await MailModel.create({
        senderId,
        senderName,
        receiverId,
        subject,
        body,
        timestamp: new Date(),
      });

      res.status(201).json(letter);
    } catch (error) {
      next(new Error("Failed to send mail"));
    }
  }
}

export default new MailController();

import UserModel from "../models/user.ts";
import HeroModel from "../models/hero.ts";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";
import { OAuth2Client } from "google-auth-library";
import { Request, Response, NextFunction } from "express";
import mongoose from "mongoose";

const GetPublicKeyOrSecret = process.env.GetPublicKeyOrSecret;
// Инициализируем клиент один раз
const googleClient = new OAuth2Client();

class UserController {
  // ==========================================
  // ПРИВАТНЫЕ ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
  // ==========================================

  private generateToken(userId: mongoose.Types.ObjectId | string) {
    if (!GetPublicKeyOrSecret) {
      throw new Error("JWT secret key is not defined in environment variables");
    }
    return jwt.sign({ id: userId }, GetPublicKeyOrSecret, { expiresIn: "30d" });
  }

  private async updateHeroStatus(
    userId: mongoose.Types.ObjectId | string,
    online: boolean,
  ) {
    const heroDoc = await HeroModel.findOneAndUpdate(
      { userId: new mongoose.Types.ObjectId(userId.toString()) },
      { online },
      { new: true },
    );
    if (!heroDoc) {
      throw new Error(`Hero for user ${userId} not found`);
    }
    return heroDoc;
  }

  private formatResponse(userDoc: any, heroDoc: any, token?: string) {
    // Преобразуем документы Mongoose в чистые JS-объекты, если это необходимо
    const user =
      typeof userDoc.toObject === "function" ? userDoc.toObject() : userDoc;
    const hero =
      typeof heroDoc.toObject === "function" ? heroDoc.toObject() : heroDoc;

    const response: any = {
      user: { ...user, id: user._id || user.id },
      hero: { ...hero },
    };
    if (token) response.token = token;

    return response;
  }

  // ==========================================
  // МЕТОДЫ КОНТРОЛЛЕРА
  // ==========================================

  async userLogin(req: Request, res: Response, next: NextFunction) {
    try {
      const { email, password } = req.body;
      const userDoc = await UserModel.findOneAndUpdate(
        { email },
        { online: true },
        { new: true },
      );

      if (!userDoc) throw new Error(`User with email ${email} not found`);

      const isPassword = await bcrypt.compare(password, userDoc.password);
      if (!isPassword) throw new Error(`Email or password is wrong`);

      const token = this.generateToken(userDoc._id);
      const heroDoc = await this.updateHeroStatus(userDoc._id, true);

      return res.status(201).json(this.formatResponse(userDoc, heroDoc, token));
    } catch (error) {
      next(error);
    }
  }

  async userGoogle(req: Request, res: Response, next: NextFunction) {
    try {
      const { credential } = req.body;
      if (!credential)
        return res.status(400).json({ error: "Токен Google отсутствует" });

      const ticket = await googleClient.verifyIdToken({
        idToken: credential,
        audience: process.env.GOOGLE_CLIENT_ID,
      });

      const payload = ticket.getPayload();
      if (!payload?.email)
        return res
          .status(400)
          .json({ error: "Не удалось прочитать данные токена или email" });

      const { email, name } = payload;
      let userDoc = await UserModel.findOne({ email });

      if (!userDoc) {
        const baseNickname = name ? name.replace(/\s+/g, "_") : "Player";
        const generatedNickname = `${baseNickname}_${Math.floor(Math.random() * 10000).toString(16)}`;
        const hashedPassword = await bcrypt.hash(
          Math.random().toString(36),
          10,
        );

        userDoc = await UserModel.create({
          nickName: generatedNickname,
          email,
          password: hashedPassword,
          online: true,
        });

        await HeroModel.create({
          userId: userDoc._id,
          nickName: userDoc.nickName,
          online: true,
        });
        console.log(
          `[Google Auth] Зарегистрирован новый игровой аккаунт: ${generatedNickname}`,
        );
      } else {
        userDoc.online = true;
        await userDoc.save();
        console.log(`[Google Auth] Игрок ${userDoc.nickName} вошел в систему`);
      }

      const token = this.generateToken(userDoc._id);
      const heroDoc = await this.updateHeroStatus(userDoc._id, true);

      return res.status(200).json(this.formatResponse(userDoc, heroDoc, token));
    } catch (error) {
      console.error("Ошибка авторизации через Google:", error);
      next(error);
    }
  }

  async addNewUser(req: Request, res: Response, next: NextFunction) {
    try {
      const { nickName, email, password } = req.body;

      if (!nickName || !email || !password) {
        return res
          .status(400)
          .json({ error: "Все поля (nickName, email, password) обязательны" });
      }

      const hashedPassword = await bcrypt.hash(password, 10);

      const newUser = await UserModel.create({
        nickName,
        email,
        password: hashedPassword,
        online: true,
      });

      const newHero = await HeroModel.create({
        userId: newUser._id,
        nickName: newUser.nickName,
        online: true,
      });
      if (!newHero)
        throw new Error(
          `Не удалось создать героя для пользователя ${newUser._id}`,
        );

      const token = this.generateToken(newUser._id);

      return res.status(201).json(this.formatResponse(newUser, newHero, token));
    } catch (error: any) {
      if (error.code === 11000) {
        const duplicateField = Object.keys(error.keyValue)[0];
        const msg =
          duplicateField === "nickName"
            ? "Этот никнейм уже занят другим игроком"
            : "Пользователь с такой электронной почтой уже зарегистрирован";
        return res.status(409).json({ error: msg });
      }
      console.error("Ошибка при регистрации пользователя:", error);
      next(error);
    }
  }

  async getCurrentUser(req: Request, res: Response, next: NextFunction) {
    try {
      const userDoc = await UserModel.findByIdAndUpdate(
        req.id,
        { online: true },
        { new: true },
      );
      if (!userDoc) throw new Error(`User with id ${req.id} not found`);

      const heroDoc = await this.updateHeroStatus(req.id as string, true);

      // Токен не нужен в этом запросе
      return res.status(201).json(this.formatResponse(userDoc, heroDoc));
    } catch (error) {
      next(error);
    }
  }

  async logOutUser(req: Request, res: Response, next: NextFunction) {
    try {
      const user = await UserModel.findByIdAndUpdate(req.id, {
        online: false,
        lastLoginDate: new Date(),
      });
      if (!user) throw new Error(`User with id ${req.id} not found`);

      await this.updateHeroStatus(req.id as string, false);

      return res.status(200).json({ message: "Logout success" });
    } catch (error) {
      next(error);
    }
  }

  async delete(req: Request, res: Response, next: NextFunction) {
    try {
      const user = await UserModel.findOneAndDelete({ _id: req.id });
      if (!user) throw new Error(`User with id ${req.id} not found`);

      const hero = await HeroModel.findOneAndDelete({
        userId: new mongoose.Types.ObjectId(user._id.toString()),
      });
      if (!hero) throw new Error(`Hero for user ${user._id} not found`);

      return res.json({ user });
    } catch (error) {
      next(error);
    }
  }
}

export default new UserController();

import { Router } from "express";
import authenticate from "../middleware/authenticate.ts";
import UserController from "../controllers/userController.ts";

export const routerAuth = Router();

routerAuth.post("/signup", UserController.addNewUser.bind(UserController));

routerAuth.post("/login", UserController.userLogin.bind(UserController));

routerAuth.post("/google", UserController.userGoogle.bind(UserController));

routerAuth.get(
  "/current",
  authenticate,
  UserController.getCurrentUser.bind(UserController),
);

routerAuth.post(
  "/logout",
  authenticate,
  UserController.logOutUser.bind(UserController),
);

routerAuth.delete(
  "/delete",
  authenticate,
  UserController.delete.bind(UserController),
);

import { Room, Client } from "colyseus";
import { UniverseState } from "./schemas/UniverseState.ts";
import { Player } from "./schemas/PlayerState.ts";
import { LocationManager } from "../game/managers/LocationManager.ts";
import { ChatManager } from "../game/managers/ChatManager.ts";
import HeroModel from "../models/hero.ts"; // Импорт твоей модели героя

export class UniverseRoom extends Room<UniverseState> {
  private locationManager!: LocationManager;
  private chatManager!: ChatManager;

  async onCreate(options: any) {
    this.setState(new UniverseState());
    this.locationManager = new LocationManager(this.state);
    this.chatManager = new ChatManager(this);

    await this.locationManager.init();

    this.setSimulationInterval(() => {
      this.locationManager.updateAllWorlds();
    }, 1000 / 60);

    // Слушаем перемещения
    this.onMessage("move", (client, data) => {
      const player = this.state.players.get(client.sessionId);
      if (player) {
        this.locationManager.handleMove(
          client.sessionId,
          player.locationId,
          data.x,
          data.z,
        );
      }
    });

    // Слушаем чат
    this.onMessage("chat_send", (client, data) => {
      this.chatManager.processMessage(client, data);
    });

    // Слушаем межпланетные перелеты
    this.onMessage("travel", (client, data) => {
      const player = this.state.players.get(client.sessionId);
      if (player && data.toLocationId) {
        this.locationManager.changeLocation(
          client.sessionId,
          player.locationId,
          data.toLocationId,
        );
      }
    });
  }

  // Игрок подключается к сокету
  async onJoin(client: Client, options: any) {
    const userId = options.userId;

    if (!userId) {
      console.error(
        `🚨 Клиент ${client.sessionId} не передал userId. Подключение разорвано.`,
      );
      client.leave();
      return;
    }

    try {
      // 1. Находим героя в MongoDB, закрепленного за этим пользователем
      const hero = await HeroModel.findOne({ userId });

      if (!hero) {
        console.error(`🚨 У пользователя ${userId} еще нет созданного героя!`);
        client.leave();
        return;
      }

      // 2. Ставим флаг онлайн в базе данных
      hero.online = true;
      await hero.save();
      console.log(
        `🚀 Герой ${hero.nickName} вошел в игру. Планета: ${hero.planet}`,
      );

      // 3. Переносим данные из твоей БД в синхронизируемый стейт Colyseus
      const player = new Player();
      player.id = client.sessionId;
      player.dbUserId = userId.toString();
      player.nickName = hero.nickName;
      player.locationId = hero.planet; // Синхронизируем планету
      player.x = hero.position?.x as number;
      player.y = hero.position?.y as number;
      player.z = hero.position?.z as number;
      this.state.players.set(client.sessionId, player);

      // 4. Инициализируем физическое тело на нужной планете с сохраненными координатами
      this.locationManager.handlePlayerJoin(
        client.sessionId,
        player.locationId,
        {
          x: player.x,
          y: player.y,
          z: player.z,
        },
      );
    } catch (error) {
      console.error(
        "🚨 Ошибка при авторизации/загрузке героя в комнату:",
        error,
      );
      client.leave();
    }
  }

  // Игрок отключается (закрыл вкладку, пропал интернет и т.д.)
  async onLeave(client: Client, consented: boolean) {
    const player = this.state.players.get(client.sessionId);

    if (player) {
      // Если игрок улетел дальше чем на 500м от центра (например, радиус планеты 100),
      // НЕ СОХРАНЯЙ эти координаты, они битые!
      const dist = Math.sqrt(player.x ** 2 + player.y ** 2 + player.z ** 2);
      if (dist > 400) {
        console.error(
          `⚠️ БАГ: Пытаемся сохранить битые координаты для ${player.nickName}: ${player.y}. Сохранение отменено!`,
        );
        // Здесь можно либо вообще не обновлять позицию,
        // либо принудительно сбросить ее на поверхность планеты
        player.y = 210;
        player.x = 0;
        player.z = 0;
      }

      try {
        // Обновляем позицию, планету и сбрасываем онлайн в твоей схеме Hero
        await HeroModel.findOneAndUpdate(
          { userId: player.dbUserId },
          {
            planet: player.locationId,
            position: {
              x: player.x,
              y: player.y,
              z: player.z,
            },
            online: false,
            updatedAt: new Date(),
          },
        );
        console.log(
          `💾 Данные героя ${player.nickName} успешно синхронизированы с MongoDB.`,
        );
      } catch (error) {
        console.error(
          `🚨 Не удалось сохранить координаты героя ${player.nickName}:`,
          error,
        );
      }

      // Чистим память сервера и физический движок
      this.locationManager.handlePlayerLeave(
        client.sessionId,
        player.locationId,
      );
      this.state.players.delete(client.sessionId);
    }
  }

  onDispose() {
    console.log("🧹 Комната вселенной уничтожена.");
  }
}

